    }

    @Test("SNOVA_24_5_4 KAT digest matches committed hash")
    func snova2454KAT() throws {
        KAT.seedDeterministicRNG()
        defer { KAT.restoreSystemRNG() }
        let key = try SNOVA24_5_4.PrivateKey()
